sql:
SELECT user_id, game_mode, points 
FROM rankings
ORDER BY points DESC;

SELECT COUNT(*) AS total_users
FROM users
WHERE user_id NOT IN (SELECT DISTINCT user_id FROM participations);

SELECT AVG(total_points) AS average_points
FROM (
  SELECT p.user_id, SUM(p.points_earned) AS total_points
  FROM participations p
  GROUP BY p.user_id
) AS subquery;

SELECT DISTINCT u.user_id, u.username, u.region, u.skill_level
FROM users u
JOIN participations p ON u.user_id = p.user_id;

SELECT u.user_id, u.username 
FROM users u 
WHERE u.user_id NOT IN (
    SELECT p.user_id 
    FROM participations p
) AND u.user_id NOT IN (
    SELECT ur.user_id 
    FROM user_rewards ur
)
ORDER BY u.join_date;

SELECT points_earned 
FROM participations 
WHERE user_id = 1;

SELECT COUNT(*) AS active_users
FROM users
WHERE is_active = 1;

external_knowledge:
- "Sail the seas of competition" refers to exploring the competitive landscape within the game;
- "Sailors who have yet to lower their sails" refers to active users (is_active = 1);
- "Chart the course" refers to compiling and organizing the ranking and performance data;
- "Winds of change in their latest charts and the ones before" refers to the comparison between current and previous ranks and points;
- "Marking the dates of their ascents and falls" refers to the tracking of ranking and points changes over time (ranking_date and PreviousRankingDate);
- "By their region and mastery" refers to sorting by region and skill level (descending);
- "The last three charts" refers to the last three ranking instances (RankNumber <= 3).

